CREATE OR REPLACE TABLE databricks_virtue_foundation_dataset_dais_2026.virtue_foundation_dataset.gold_nfhs_district AS
SELECT
  CASE WHEN regexp_replace(trim(state_ut),'\\s+',' ')='Maharastra' THEN 'Maharashtra' ELSE regexp_replace(trim(state_ut),'\\s+',' ') END AS state_ut_norm,
  regexp_replace(trim(district_name),'\\s+',' ') AS district_name_norm,
  state_ut AS state_ut_raw,
  district_name AS district_name_raw,
  CAST(CAST(NULLIF(regexp_replace(trim(CAST(households_surveyed AS STRING)),'[()]',''),'*') AS DOUBLE) AS BIGINT) AS households_surveyed,
  CAST(CAST(NULLIF(regexp_replace(trim(CAST(women_15_49_interviewed AS STRING)),'[()]',''),'*') AS DOUBLE) AS BIGINT) AS women_15_49_interviewed,
  CAST(CAST(NULLIF(regexp_replace(trim(CAST(men_15_54_interviewed AS STRING)),'[()]',''),'*') AS DOUBLE) AS BIGINT) AS men_15_54_interviewed,
  CAST(NULLIF(regexp_replace(trim(CAST(female_population_age_6_years_and_above_ever_schooled_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS female_ever_schooled_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(population_below_age_15_years_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS population_under_15_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(sex_ratio_total_f_per_1000_m AS STRING)),'[()]',''),'*') AS DOUBLE) AS sex_ratio_total_f_per_1000_m,
  CAST(NULLIF(regexp_replace(trim(CAST(sex_ratio_at_birth_5y_f_per_1000_m AS STRING)),'[()]',''),'*') AS DOUBLE) AS sex_ratio_at_birth_f_per_1000_m,
  CAST(NULLIF(regexp_replace(trim(CAST(child_u5_whose_birth_was_civil_reg_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_u5_birth_registered_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(deaths_in_the_last_3_years_civil_reg_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS deaths_3y_registered_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(hh_electricity_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS hh_electricity_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(hh_improved_water_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS hh_improved_water_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(hh_use_improved_sanitation_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS hh_improved_sanitation_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(households_using_clean_fuel_for_cooking_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS hh_clean_cooking_fuel_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(households_using_iodized_salt_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS hh_iodized_salt_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(hh_member_covered_health_insurance_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS hh_any_health_insurance_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_5y_who_attended_pre_primary_school_during_the_school_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_u5_attended_pre_primary_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(women_age_15_49_who_are_literate_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_15_49_literate_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(women_age_15_49_with_10_or_more_years_of_schooling_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_15_49_schooling_10yr_plus_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(w20_24_married_before_age_18_years_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_20_24_married_before_18_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(births_in_the_5_years_preceding_the_survey_that_are_birth_3_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS births_birth_order_3plus_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(w15_19_who_were_already_mothers_or_pregnant_at_the_time_of_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_15_19_mothers_or_pregnant_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(w15_24_who_use_menstrual_hygiene_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_15_24_use_menstrual_hygiene_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(fp_cm_w15_49_any_method_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS fp_any_method_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(fp_cm_w15_49_modern_method_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS fp_modern_method_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(fp_cm_w15_49_f_steril_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS fp_female_sterilization_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(fp_cm_w15_49_m_steril_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS fp_male_sterilization_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(fp_cm_w15_49_iud_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS fp_iud_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(fp_cm_w15_49_pill_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS fp_pill_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(fp_cm_w15_49_condom_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS fp_condom_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(fp_cm_w15_49_injectables_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS fp_injectables_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(fp_unmet_total_cm_w15_49_7_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS fp_unmet_need_total_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(fp_unmet_spacing_cm_w15_49_7_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS fp_unmet_need_spacing_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(health_worker_ever_talked_to_female_non_users_about_family_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS fp_hw_counselled_nonusers_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(current_users_ever_told_about_side_effects_of_current_metho_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS fp_users_told_side_effects_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(mothers_who_had_an_anc_visit_in_the_first_trimester_lb5y_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS anc_first_trimester_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(mothers_who_had_at_least_4_anc_visits_lb5y_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS anc_4plus_visits_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(mothers_whose_last_birth_was_protected_against_neo_tetanus_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS neonatal_tetanus_protection_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(mothers_who_consumed_ifa_for_100_days_or_more_when_they_wer_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS ifa_100days_plus_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(mothers_who_consumed_ifa_for_180_days_or_more_when_they_wer_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS ifa_180days_plus_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(registered_pregnancies_for_which_the_mother_received_a_mcp_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS mcp_card_received_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(mothers_who_received_pnc_from_a_doctor_nurse_lhv_anm_midwif_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS pnc_skilled_provider_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(average_out_of_pocket_expenditure_per_delivery_in_a_public_fac AS STRING)),'[()]',''),'*') AS DOUBLE) AS oop_expenditure_per_delivery_public_inr,
  CAST(NULLIF(regexp_replace(trim(CAST(children_born_at_home_who_were_taken_to_a_health_facility_f_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS home_birth_taken_to_facility_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(children_who_received_pnc_from_a_doctor_nurse_lhv_anm_midwi_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS newborn_pnc_skilled_provider_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(institutional_birth_5y_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS institutional_birth_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(institutional_birth_in_public_facility_5y_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS institutional_birth_public_facility_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(home_birth_that_were_conducted_by_skilled_hp_5y_10_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS home_birth_skilled_attendant_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(births_attended_by_skilled_hp_5y_10_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS births_skilled_attendant_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(births_delivered_by_csection_5y_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS csection_birth_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(births_in_a_private_fac_that_were_delivered_by_csection_5y_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS csection_private_facility_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(births_in_a_public_fac_that_were_delivered_by_csection_5y_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS csection_public_facility_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_12_23m_fully_vaccinated_based_on_information_from_eit_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_12_23m_fully_vaccinated_card_or_recall_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_12_23m_fully_vaccinated_based_on_information_from_vax_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_12_23m_fully_vaccinated_vax_card_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_12_23m_who_have_received_bcg_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_12_23m_bcg_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_12_23m_who_have_received_3_doses_of_polio_vaccine_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_12_23m_polio3_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_12_23m_who_have_received_3_doses_of_penta_or_dpt_vacc_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_12_23m_penta_or_dpt3_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_12_23m_who_have_received_the_first_dose_of_mcv_mcv_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_12_23m_mcv1_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_24_35m_who_have_received_a_second_dose_of_mcv_mcv_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_24_35m_mcv2_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_12_23m_who_have_received_3_doses_of_rotavirus_vaccine_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_12_23m_rotavirus3_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_12_23m_who_have_received_3_doses_of_penta_or_hepatiti_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_12_23m_penta_or_hepb3_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_9_35m_who_received_a_vit_a_in_the_last_6_months_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_9_35m_vitamin_a_last_6m_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_12_23m_who_received_most_of_their_vaccinations_in_a_p_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_12_23m_vax_mostly_public_facility_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_12_23m_who_received_most_of_their_vaccinations_in_a_2_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_12_23m_vax_mostly_private_facility_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(prev_diarrhoea_2wk_child_u5_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS diarrhoea_prev_u5_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(children_with_diarrhoea_2wk_who_received_oral_rehydration_s_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS diarrhoea_ors_received_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(children_with_diarrhoea_2wk_who_received_zinc_child_u5_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS diarrhoea_zinc_received_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(children_with_diarrhoea_2wk_taken_to_a_health_facility_or_h_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS diarrhoea_care_seeking_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(children_prev_symptoms_of_acute_respiratory_infection_ari_2_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS ari_prev_u5_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(children_with_fever_or_symptoms_of_ari_2wk_taken_to_a_healt_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS fever_ari_care_seeking_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(children_under_age_3_years_breastfed_within_one_hour_of_bir_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS early_breastfeeding_initiation_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_u6m_exclusively_breastfed_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS exclusive_breastfeeding_u6m_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_6_8m_receiving_solid_or_semi_solid_food_and_breastmil_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS complementary_feeding_intro_6_8m_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(breastfeeding_child_6_23m_receiving_an_adequate_diet16_17_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS breastfeeding_6_23m_adequate_diet_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(non_breastfeeding_child_6_23m_receiving_an_adequate_diet16_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS non_breastfeeding_6_23m_adequate_diet_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(total_child_6_23m_receiving_an_adequate_diet16_17_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS total_6_23m_adequate_diet_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_u5_who_are_stunted_height_for_age_18_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_u5_stunted_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_u5_who_are_wasted_weight_for_height_18_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_u5_wasted_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_u5_who_are_severe_wasted_weight_for_height_19_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_u5_severe_wasted_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_u5_who_are_underweight_weight_for_age_18_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_u5_underweight_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_u5_who_are_overweight_weight_for_height_20_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_u5_overweight_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(women_age_15_49_years_whose_bmi_bmi_is_underweight_bmi_lt_1_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_underweight_bmi_lt185_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(women_age_15_49_years_who_are_overweight_obese_bmi_gte_25_0_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_overweight_obese_bmi_gte25_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(women_age_15_49_years_who_have_high_risk_whr_gte_0_85_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_high_risk_whr_gte085_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(child_6_59m_who_are_anaemic_lt_11_0_g_dl_22_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS child_6_59m_anaemic_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(non_pregnant_w15_49_who_are_anaemic_lt_12_0_g_dl_22_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS nonpregnant_women_anaemic_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(pregnant_w15_49_who_are_anaemic_lt_11_0_g_dl_22_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS pregnant_women_anaemic_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(all_w15_49_who_are_anaemic_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS all_women_15_49_anaemic_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(all_w15_19_who_are_anaemic_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS adolescent_girls_15_19_anaemic_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(women_age_15_years_and_above_with_high_141_160_mg_dl_blood_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_15plus_high_blood_sugar_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(w15_plus_with_very_high_gt_160_mg_dl_blood_sugar_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_15plus_very_high_blood_sugar_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(w15_plus_with_high_or_very_high_gt_140_mg_dl_blood_sugar_or_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_15plus_high_blood_sugar_or_meds_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(m15_plus_with_high_141_160_mg_dl_blood_sugar_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS men_15plus_high_blood_sugar_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(men_age_15_years_and_above_with_very_high_gt_160_mg_dl_bloo_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS men_15plus_very_high_blood_sugar_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(m15_plus_with_high_or_very_high_gt_140_mg_dl_blood_sugar_or_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS men_15plus_high_blood_sugar_or_meds_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(w15_plus_with_mildly_high_bp_sys_140_159_mmhg_and_or_dia_90_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_15plus_mildly_high_bp_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(w15_plus_with_moderately_or_severely_high_bp_sys_gte_160_mm_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_15plus_moderate_severe_high_bp_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(w15_plus_with_high_bp_sys_gte_140_mmhg_and_or_dia_gte_90_mm_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_15plus_high_bp_or_meds_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(m15_plus_with_mildly_high_bp_sys_140_159_mmhg_and_or_dia_90_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS men_15plus_mildly_high_bp_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(m15_plus_with_moderately_or_severely_high_bp_sys_gte_160_mm_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS men_15plus_moderate_severe_high_bp_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(m15_plus_with_high_bp_sys_gte_140_mmhg_and_or_dia_gte_90_mm_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS men_15plus_high_bp_or_meds_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(women_age_30_49_years_ever_undergone_a_cervical_screen_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_30_49_cervical_screen_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(women_age_30_49_years_ever_undergone_a_breast_exam_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_30_49_breast_exam_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(women_age_30_49_years_ever_undergone_an_oral_cancer_exam_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_30_49_oral_cancer_exam_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(w15_plus_who_use_any_kind_of_tobacco_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_15plus_tobacco_use_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(m15_plus_who_use_any_kind_of_tobacco_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS men_15plus_tobacco_use_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(w15_plus_who_consume_alcohol_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS women_15plus_alcohol_use_pct,
  CAST(NULLIF(regexp_replace(trim(CAST(m15_plus_who_consume_alcohol_pct AS STRING)),'[()]',''),'*') AS DOUBLE) AS men_15plus_alcohol_use_pct
FROM databricks_virtue_foundation_dataset_dais_2026.virtue_foundation_dataset.nfhs_5_district_health_indicators;